import {
  usePersistedFilter,
  usePersistedFilterMutation,
} from './usePersistedFilter.js';
import { useRecentAndPinnedFiltersStore } from './useRecentFiltersStore.js';
import { type StoredFilter } from '../../state/recent-pinned-store.js';

/**
 * Allows access to the namespaced pinned filters store.
 */
export function usePinnedFilters(name: string | null = null): StoredFilter[] {
  const setFilters = useRecentAndPinnedFiltersStore(
    (state) => state.setPinnedFilters,
    name,
  );
  const filters = useRecentAndPinnedFiltersStore(
    (state) => state.pinnedFilters,
    name,
  );

  usePersistedFilter(
    name,
    `strato-FilterField-pinnedFilters-${name}`,
    setFilters,
  );

  return filters;
}

/**
 * Allows access to the namespaced recent filters store setter.
 * @internal
 */
export function usePinnedFilterMutation(name: string | null = null) {
  const { mutate: pinFilter } = usePersistedFilterMutation(
    `strato-FilterField-pinnedFilters-${name}`,
    name,
    'pin',
  );

  const { mutate: unpinFilter } = usePersistedFilterMutation(
    `strato-FilterField-pinnedFilters-${name}`,
    name,
    'unpin',
  );

  return {
    pinFilter,
    unpinFilter,
  };
}
